const feeds = [
  { name: 'Hacker News', url: 'https://hnrss.org/newest?q=AI+OR+artificial+intelligence+OR+LLM+OR+GPT+OR+Claude&points=50' },
  { name: 'Ars Technica', url: 'https://feeds.arstechnica.com/arstechnica/technology-lab' },
  { name: 'TechCrunch AI', url: 'https://techcrunch.com/category/artificial-intelligence/feed/' },
  { name: 'The Verge AI', url: 'https://www.theverge.com/rss/ai-artificial-intelligence/index.xml' },
  { name: 'Google AI Blog', url: 'https://blog.google/technology/ai/rss/' },
  { name: 'DeepMind Blog', url: 'https://deepmind.google/blog/rss.xml' },
  { name: 'Anthropic Blog', url: 'https://www.anthropic.com/rss.xml' },
  { name: 'OpenAI Blog', url: 'https://openai.com/blog/rss.xml' },
  { name: "Ben's Bites", url: 'https://bensbites.beehiiv.com/feed' }
];

const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
const allArticles = [];
const errors = [];

function extractText(xml, tag) {
  const regex = new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]>|<${tag}[^>]*>([\\s\\S]*?)</${tag}>`, 'gi');
  const matches = [];
  let m;
  while ((m = regex.exec(xml)) !== null) {
    matches.push((m[1] || m[2] || '').trim());
  }
  return matches;
}

function extractLinks(xml) {
  const links = [];
  const linkTagRegex = /<link[^>]*><!\[CDATA\[([\s\S]*?)\]\]>|<link[^>]*>([\s\S]*?)<\/link>/gi;
  let m;
  while ((m = linkTagRegex.exec(xml)) !== null) {
    links.push((m[1] || m[2] || '').trim());
  }
  const atomLinkRegex = /<link[^>]*href=["']([^"']+)["'][^>]*\/?>(?:<\/link>)?/gi;
  while ((m = atomLinkRegex.exec(xml)) !== null) {
    if (m[1] && !m[1].includes('application/')) {
      links.push(m[1].trim());
    }
  }
  return links;
}

for (const feed of feeds) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      returnFullResponse: false,
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; n8n-news-digest/1.0)',
        'Accept': 'application/rss+xml, application/xml, text/xml, application/atom+xml, */*'
      },
      timeout: 15000
    });

    const xml = typeof response === 'string' ? response : JSON.stringify(response);
    const itemRegex = /<item[\s>][\s\S]*?<\/item>|<entry[\s>][\s\S]*?<\/entry>/gi;
    const items = xml.match(itemRegex) || [];

    let feedCount = 0;
    const MAX_PER_FEED = 10;
    for (const item of items) {
      if (feedCount >= MAX_PER_FEED) break;
      const titles = extractText(item, 'title');
      const title = titles[0] || 'Untitled';
      const itemLinks = extractLinks(item);
      const link = itemLinks[0] || '';
      const descriptions = extractText(item, 'description').concat(extractText(item, 'summary')).concat(extractText(item, 'content'));
      let description = descriptions[0] || '';
      description = description.replace(/<[^>]+>/g, '').substring(0, 300);
      const pubDates = extractText(item, 'pubDate').concat(extractText(item, 'published')).concat(extractText(item, 'updated'));
      const pubDateStr = pubDates[0] || '';
      const pubDate = pubDateStr ? new Date(pubDateStr) : null;

      if (pubDate && pubDate >= cutoff) {
        allArticles.push({ source: feed.name, title, link, description, pubDate: pubDate.toISOString() });
        feedCount++;
      } else if (!pubDate) {
        allArticles.push({ source: feed.name, title, link, description, pubDate: 'unknown' });
        feedCount++;
      }
    }
  } catch (e) {
    errors.push({ source: feed.name, error: e.message || String(e) });
  }
}

allArticles.sort((a, b) => {
  if (a.pubDate === 'unknown') return 1;
  if (b.pubDate === 'unknown') return -1;
  return new Date(b.pubDate) - new Date(a.pubDate);
});

const bySource = {};
for (const article of allArticles) {
  if (!bySource[article.source]) bySource[article.source] = [];
  bySource[article.source].push(article);
}

const dateLabel = new Date().toISOString().split('T')[0];

return [{ json: {
  dateLabel,
  totalArticles: allArticles.length,
  articles: allArticles,
  bySource,
  errors,
  generatedAt: new Date().toISOString()
} }];

const response = $input.first().json;
const markdown = response.content[0].text;

// Parse markdown into email-safe HTML (table-based, no CSS3)
const lines = markdown.split('\n');
let bodyHtml = '';
let inList = false;
let sectionCount = 0;

function inlineStyles(text) {
  let s = text;
  s = s.replace(/\*\*HIGH\*\*/g, '<span style="background-color:#dc2626; color:#ffffff; padding:2px 8px; font-size:11px; font-weight:bold;">HIGH</span>');
  s = s.replace(/\*\*MED\*\*/g, '<span style="background-color:#d97706; color:#ffffff; padding:2px 8px; font-size:11px; font-weight:bold;">MED</span>');
  s = s.replace(/\*\*LOW\*\*/g, '<span style="background-color:#6b7280; color:#ffffff; padding:2px 8px; font-size:11px; font-weight:bold;">LOW</span>');
  s = s.replace(/\*\*(.+?)\*\*/g, '<strong style="color:#e2e8f0;">$1</strong>');
  s = s.replace(/\*(.+?)\*/g, '<em>$1</em>');
  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" style="color:#a78bfa; text-decoration:underline;">$1</a>');
  return s;
}

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    continue;
  }
  if (trimmed.startsWith('### ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    bodyHtml += `<h3 style="color:#e2e8f0; font-size:16px; margin:18px 0 6px 0; font-weight:bold; font-family:Arial,sans-serif;">${trimmed.slice(4)}</h3>`;
  } else if (trimmed.startsWith('## ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    sectionCount++;
    const border = sectionCount > 1 ? '<tr><td style="padding:12px 0 0 0; border-top:1px solid #2d1b69;"></td></tr>' : '';
    bodyHtml += `<table width="100%" cellpadding="0" cellspacing="0" border="0">${border}<tr><td style="padding:${sectionCount > 1 ? '16' : '0'}px 0 10px 0;"><h2 style="color:#c4b5fd; font-size:20px; margin:0; font-weight:bold; font-family:Arial,sans-serif;">${trimmed.slice(3)}</h2></td></tr></table>`;
  } else if (trimmed.startsWith('# ')) {
    if (inList) { bodyHtml += '</table>'; inList = false; }
  } else if (trimmed.startsWith('- ')) {
    if (!inList) { bodyHtml += '<table width="100%" cellpadding="0" cellspacing="0" border="0">'; inList = true; }
    const content = inlineStyles(trimmed.slice(2));
    bodyHtml += `<tr><td style="padding:6px 0;"><table width="100%" cellpadding="0" cellspacing="0" border="0"><tr><td width="4" style="background-color:#7c3aed;"></td><td style="padding:10px 14px; background-color:#1a1030; font-family:Arial,sans-serif; font-size:14px; color:#cbd5e1; line-height:1.5;">${content}</td></tr></table></td></tr>`;
  } else {
    if (inList) { bodyHtml += '</table>'; inList = false; }
    bodyHtml += `<p style="color:#cbd5e1; line-height:1.6; margin:8px 0; font-family:Arial,sans-serif; font-size:14px;">${inlineStyles(trimmed)}</p>`;
  }
}
if (inList) bodyHtml += '</table>';

const dateLabel = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const html = `<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd"><html xmlns="http://www.w3.org/1999/xhtml"><head><meta http-equiv="Content-Type" content="text/html; charset=utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>AI News Digest</title></head><body style="margin:0; padding:0; background-color:#0f0b1a; -webkit-text-size-adjust:100%;">
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#0f0b1a;"><tr><td align="center" style="padding:0;">
<table width="660" cellpadding="0" cellspacing="0" border="0" style="max-width:660px; width:100%;">
  <!-- Header -->
  <tr><td style="background-color:#1e1040; padding:36px 32px 28px 32px; border-bottom:3px solid #7c3aed;">
    <table width="100%" cellpadding="0" cellspacing="0" border="0"><tr>
      <td style="font-family:Arial,sans-serif;">
        <div style="font-size:12px; color:#a78bfa; text-transform:uppercase; letter-spacing:3px; font-weight:bold; margin-bottom:10px;">&#x1F916; Daily Intelligence</div>
        <h1 style="color:#f1f5f9; font-size:26px; margin:0 0 6px 0; font-weight:bold; font-family:Arial,sans-serif;">AI News Digest</h1>
        <div style="color:#94a3b8; font-size:13px; font-family:Arial,sans-serif;">${dateLabel}</div>
      </td>
      <td width="80" valign="top" style="text-align:right; font-size:48px; color:#2d1b69;">&#x2B22;</td>
    </tr></table>
  </td></tr>
  <!-- Body -->
  <tr><td style="background-color:#130f24; padding:28px 32px;">
    ${bodyHtml}
  </td></tr>
  <!-- Footer -->
  <tr><td style="background-color:#0f0b1a; padding:20px 32px; border-top:1px solid #2d1b69; text-align:center; font-family:Arial,sans-serif;">
    <div style="color:#64748b; font-size:12px;">Powered by n8n</div>
    <div style="color:#475569; font-size:11px; margin-top:4px;">9 RSS sources &middot; Curated daily</div>
  </td></tr>
</table>
</td></tr></table>
</body></html>`;

const buffer = Buffer.from(markdown, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'ai-news.md', 'text/markdown');

return [{ json: { markdown, html }, binary: { data: binaryData } }];
